const item = $input.first();
const codeFence = '```';

function parseAgentOutput(value) {
  if (value && typeof value === 'object') return value;
  if (typeof value !== 'string') return {};

  let text = value.trim();
  if (text.startsWith(codeFence)) {
    text = text.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  }

  const firstBrace = text.indexOf('{');
  const lastBrace = text.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    text = text.slice(firstBrace, lastBrace + 1);
  }

  try {
    return JSON.parse(text);
  } catch (error) {
    return { _parse_error: error.message };
  }
}

function normalizeArray(value) {
  if (Array.isArray(value)) return value.map((entry) => String(entry)).filter(Boolean);
  if (value === undefined || value === null || value === '') return [];
  return [String(value)];
}

function cleanText(value, fallback) {
  const text = String(value || '').trim();
  return text || fallback;
}

const validatedItems = $items('Validate AI Evaluation');
const validated = validatedItems[0] ? validatedItems[0].json : {};
const rawTriage = item.json.output !== undefined ? item.json.output : item.json;
const triage = parseAgentOutput(rawTriage);
const routeNotes = [];

const allowedStatuses = ['auto_shortlist_alert', 'review_needed_alert', 'log_only', 'blocked'];
let triageStatus = String(triage.triage_status || '').trim();
const invalidTriage = !allowedStatuses.includes(triageStatus) || Boolean(triage._parse_error);
if (invalidTriage) {
  routeNotes.push('Triage agent output invalid; deterministic route set to blocked');
  triageStatus = 'blocked';
}

let automationConfidence = Number(triage.automation_confidence);
if (!Number.isFinite(automationConfidence)) {
  routeNotes.push('Automation confidence missing or invalid; set to 0');
  automationConfidence = 0;
}
automationConfidence = Math.min(1, Math.max(0, automationConfidence));

const decision = String(validated.decision || '');
const auditStatus = String(validated.audit_status || '');
const auditConfidence = Number(validated.audit_confidence) || 0;
const totalScore = Number(validated.total_score) || 0;
const cvTextLength = Number(validated.cv_text_length) || 0;
const ocrPages = Number(validated.ocr_pages) || 0;

let finalRoute = 'log_only';
if (cvTextLength < 50 || ocrPages < 1) {
  finalRoute = 'blocked';
  routeNotes.push('Route blocked because OCR text is unreadable or missing');
} else if (auditStatus === 'Fail') {
  finalRoute = 'blocked';
  routeNotes.push('Route blocked because evidence audit failed');
} else if (invalidTriage) {
  finalRoute = 'blocked';
} else if (decision === 'Shortlist' && auditStatus === 'Pass' && totalScore >= 75 && auditConfidence >= 0.75 && automationConfidence >= 0.75) {
  finalRoute = 'auto_shortlist_alert';
} else if (decision === 'Shortlist' && totalScore >= 75 && (auditStatus === 'Warn' || auditConfidence < 0.75 || automationConfidence < 0.75)) {
  finalRoute = 'review_needed_alert';
  routeNotes.push('Recruiter review required before treating this as a clean shortlist');
} else {
  finalRoute = 'log_only';
}

const emailAllowed = finalRoute === 'auto_shortlist_alert' || finalRoute === 'review_needed_alert';
const defaultPriority = finalRoute === 'auto_shortlist_alert' ? 'High' : finalRoute === 'review_needed_alert' ? 'Medium' : finalRoute === 'blocked' ? 'Blocked' : 'Low';
const recruiterPriority = ['High', 'Medium', 'Low', 'Blocked'].includes(String(triage.recruiter_priority || '').trim())
  ? String(triage.recruiter_priority).trim()
  : defaultPriority;

const emailType = finalRoute === 'auto_shortlist_alert'
  ? 'shortlist_passed_audit'
  : finalRoute === 'review_needed_alert'
    ? 'review_needed'
    : finalRoute;

const candidateName = validated.candidate_name || 'Candidate';
const jobRole = validated.job_role || 'AI Automation Engineer';
const defaultSubject = finalRoute === 'auto_shortlist_alert'
  ? 'Audit-passed shortlist: ' + candidateName + ' - ' + jobRole
  : finalRoute === 'review_needed_alert'
    ? 'Review needed: ' + candidateName + ' - ' + jobRole
    : 'Logged candidate: ' + candidateName + ' - ' + jobRole;

const routeReason = cleanText(
  triage.route_reason,
  finalRoute === 'auto_shortlist_alert'
    ? 'Shortlist decision passed the evidence audit and met automation confidence thresholds.'
    : finalRoute === 'review_needed_alert'
      ? 'Candidate is strong, but evidence audit or automation confidence requires recruiter review.'
      : finalRoute === 'blocked'
        ? 'Deterministic safety gate blocked automated recruiter notification.'
        : 'Candidate logged without recruiter notification.'
);

const recruiterMessage = cleanText(
  triage.recruiter_message,
  routeReason
);

return [{
  json: {
    ...validated,
    workflow_version: 'v4-autonomous-triage',
    triage_status: triageStatus,
    final_route: finalRoute,
    recruiter_priority: recruiterPriority,
    automation_confidence: Number(automationConfidence.toFixed(2)),
    recruiter_email_type: emailType,
    recruiter_subject: cleanText(triage.recruiter_subject, defaultSubject),
    recruiter_message: recruiterMessage,
    recommended_next_step: cleanText(triage.recommended_next_step, validated.recommended_action || 'Review the logged screening result.'),
    interview_focus_areas: normalizeArray(triage.interview_focus_areas).join('; '),
    risk_flags: normalizeArray(triage.risk_flags).join('; '),
    missing_information: normalizeArray(triage.missing_information).join('; '),
    route_reason: routeReason + (routeNotes.length ? ' Route notes: ' + routeNotes.join('; ') + '.' : ''),
    route_validation_notes: routeNotes.join('; ') || 'passed',
    email_allowed: emailAllowed,
    triage_raw_output: rawTriage,
  },
}];

